#[async_trait]
impl<R: SAMLProviderProjectionRepository> SAMLProviderEventHandler for SAMLProviderProjector<R> {

    async fn on_created(&self, event: SAMLProviderCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = SAMLProviderProjection::new(
            event.id,
            event.name,
            event.display_name,
            event.entity_id,
            event.sso_url,
            event.slo_url,
            event.certificate,
            event.acs_url,
            event.sls_url,
            event.name_id_format,
            event.attribute_mapping,
            event.is_active,
            event.status,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: SAMLProviderUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.name = event.name;
            projection.display_name = event.display_name;
            projection.entity_id = event.entity_id;
            projection.sso_url = event.sso_url;
            projection.slo_url = event.slo_url;
            projection.certificate = event.certificate;
            projection.acs_url = event.acs_url;
            projection.sls_url = event.sls_url;
            projection.name_id_format = event.name_id_format;
            projection.attribute_mapping = event.attribute_mapping;
            projection.is_active = event.is_active;
            projection.status = event.status;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: SAMLProviderDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

